external_knowledge:
- The term 'growth measurements' refers to height, weight, BMI, percentile height, percentile weight, and percentile BMI; 
- 'Latest communications' encompasses communication date, type, and message; 
- 'Educational content' includes title and URL; 
- The 'last year' is defined as the period from the current date minus one year.

sql:
SELECT height
FROM growth_data
WHERE child_id = 1;

SELECT child_name
FROM children
ORDER BY child_name;

SELECT title
FROM educational_content
WHERE content_type = 'video';

SELECT COUNT(content_id) AS content_count
FROM educational_content
WHERE created_date LIKE '2023-%';

SELECT MAX(measurement_date) AS most_recent_date
FROM growth_data
WHERE child_id = 1;

SELECT child_name 
FROM children 
ORDER BY child_name;

SELECT age_range
FROM age_groups
ORDER BY age_range ASC;

SELECT MAX(communication_date) AS most_recent_communication_date
FROM communications
WHERE child_id = 1;

SELECT COUNT(*) AS communication_count
FROM communications
WHERE child_id = 0;

SELECT DISTINCT p.parent_name
FROM parents p
JOIN communications c ON p.parent_id = c.parent_id;

SELECT AVG(height) AS average_height
  FROM growth_data
  WHERE age_group_id = (SELECT age_group_id FROM age_groups WHERE age_range = '3/4 years');
